{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://kapow.dev/schemas/product-contract.schema.json",
  "title": "Product Contract",
  "description": "Schema for product-facing contracts that define user-visible features, pages, integrations, and data-quality promises.",
  "type": "object",
  "required": ["id", "title", "description", "status", "owner", "category"],
  "additionalProperties": false,
  "properties": {
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+(-[a-z0-9]+)*$",
      "description": "Unique identifier in kebab-case (e.g., 'institution-search')."
    },
    "title": {
      "type": "string",
      "minLength": 1,
      "description": "Human-readable name of the contract."
    },
    "description": {
      "type": "string",
      "minLength": 1,
      "description": "What this contract promises to users."
    },
    "status": {
      "type": "string",
      "enum": ["shipped", "experimental", "planned", "deprecated"],
      "description": "Current lifecycle status."
    },
    "owner": {
      "type": "string",
      "minLength": 1,
      "description": "Team or person responsible for this contract."
    },
    "category": {
      "type": "string",
      "enum": ["feature", "page", "integration", "data-quality"],
      "description": "Type of product contract."
    },
    "user_story": {
      "type": "string",
      "description": "User story in 'As a ... I can ...' format."
    },
    "acceptance_criteria": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Conditions that must be true for this contract to be considered fulfilled."
    },
    "source_files": {
      "type": "array",
      "items": { "type": "string" },
      "description": "File paths (relative to repo root) that implement this contract."
    },
    "tests": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Test file paths or test name patterns that verify this contract."
    },
    "issues": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^kapow-[a-z0-9]+",
        "description": "Beads issue ID."
      },
      "description": "Linked beads issue IDs."
    },
    "evidence": {
      "type": "object",
      "required": ["type"],
      "additionalProperties": false,
      "properties": {
        "type": {
          "type": "string",
          "enum": ["test", "manual", "monitoring", "assertion"],
          "description": "How the contract claim is verified."
        },
        "description": {
          "type": "string",
          "description": "Details about the verification method."
        },
        "references": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Links to test runs, dashboards, or other proof."
        }
      },
      "description": "How this contract is verified."
    },
    "created": {
      "type": "string",
      "format": "date",
      "description": "Date the contract was created (YYYY-MM-DD)."
    },
    "updated": {
      "type": "string",
      "format": "date",
      "description": "Date the contract was last updated (YYYY-MM-DD)."
    }
  }
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://kapow.dev/schemas/technical-contract.schema.json",
  "title": "Technical Contract",
  "description": "Schema for technical contracts that define system-level guarantees: API behavior, search invariants, auth rules, data integrity, and performance bounds.",
  "type": "object",
  "required": ["id", "title", "description", "status", "owner", "category"],
  "additionalProperties": false,
  "properties": {
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+(-[a-z0-9]+)*$",
      "description": "Unique identifier in kebab-case (e.g., 'search-validation-parity')."
    },
    "title": {
      "type": "string",
      "minLength": 1,
      "description": "Human-readable name of the contract."
    },
    "description": {
      "type": "string",
      "minLength": 1,
      "description": "What this contract guarantees at the system level."
    },
    "status": {
      "type": "string",
      "enum": ["shipped", "experimental", "planned", "deprecated"],
      "description": "Current lifecycle status."
    },
    "owner": {
      "type": "string",
      "minLength": 1,
      "description": "Team or person responsible for this contract."
    },
    "category": {
      "type": "string",
      "enum": ["api", "search", "auth", "data", "performance", "infrastructure"],
      "description": "Type of technical contract."
    },
    "guarantees": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["description"],
        "additionalProperties": false,
        "properties": {
          "description": {
            "type": "string",
            "description": "What is guaranteed."
          },
          "metric": {
            "type": "string",
            "description": "Measurable metric (e.g., 'p99 latency', 'error rate')."
          },
          "threshold": {
            "type": "string",
            "description": "Acceptable bound (e.g., '< 500ms', '0%', '>= 99.9%')."
          }
        }
      },
      "description": "Specific technical guarantees this contract makes."
    },
    "dependencies": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^[a-z0-9]+(-[a-z0-9]+)*$"
      },
      "description": "IDs of other contracts this one depends on."
    },
    "source_files": {
      "type": "array",
      "items": { "type": "string" },
      "description": "File paths (relative to repo root) that implement this contract."
    },
    "tests": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Test file paths or test name patterns that verify this contract."
    },
    "issues": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^kapow-[a-z0-9]+",
        "description": "Beads issue ID."
      },
      "description": "Linked beads issue IDs."
    },
    "evidence": {
      "type": "object",
      "required": ["type"],
      "additionalProperties": false,
      "properties": {
        "type": {
          "type": "string",
          "enum": ["test", "manual", "monitoring", "assertion"],
          "description": "How the contract claim is verified."
        },
        "description": {
          "type": "string",
          "description": "Details about the verification method."
        },
        "references": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Links to test runs, dashboards, or other proof."
        }
      },
      "description": "How this contract is verified."
    },
    "created": {
      "type": "string",
      "format": "date",
      "description": "Date the contract was created (YYYY-MM-DD)."
    },
    "updated": {
      "type": "string",
      "format": "date",
      "description": "Date the contract was last updated (YYYY-MM-DD)."
    }
  }
}

{
  "id": "search-validation-parity",
  "title": "Search Validation Parity",
  "description": "All three search entry points (GraphQL, CSV export, MCP) apply identical validation rules, producing the same accept/reject decisions for any given request.",
  "status": "shipped",
  "owner": "core",
  "category": "search",
  "guarantees": [
    {
      "description": "Invalid filter names are rejected with the same error message across all entry points."
    },
    {
      "description": "Auth-restricted fields return 'unauthorized' errors for unauthenticated requests across all entry points."
    },
    {
      "description": "Pagination bounds (limit 1-1000) are enforced identically across all entry points."
    },
    {
      "description": "Geographic radius constraints (1-500 miles) are enforced identically across all entry points."
    }
  ],
  "dependencies": [],
  "source_files": [
    "api/internal/search/validate.go",
    "api/internal/search/contract.go",
    "api/internal/handler/export.go",
    "api/internal/mcp/search.go",
    "api/graph/resolver/schema.resolvers.go"
  ],
  "tests": [
    "api/internal/search/contract_test.go",
    "api/internal/handler/contract_test.go",
    "api/internal/mcp/contract_test.go"
  ],
  "issues": [
    "kapow-4vy"
  ],
  "evidence": {
    "type": "test",
    "description": "Shared ContractCase test matrix (~20 cases) runs against all three entry points. Each adapter translates entry-point-specific request/response formats but delegates to the same search.ValidateRequest function.",
    "references": [
      "api/internal/search/contract.go"
    ]
  },
  "created": "2026-03-10",
  "updated": "2026-03-10"
}

